"""Dataset configuration models for flexible dataset loading."""

import json
from pathlib import Path
from typing import Any, Dict, Optional

from pydantic import BaseModel, Field, field_validator


class DatasetSourceConfig(BaseModel):
    """Configuration for a dataset source.

    Supports multiple dataset source types:
    - file: Local files (txt, csv, json)
    - huggingface: HuggingFace Hub datasets
    - custom: Custom dataset loaders
    """

    type: str = Field(
        ..., description="Dataset source type: 'file', 'huggingface', or 'custom'"
    )
    path: Optional[str] = Field(
        None, description="Path to dataset (file path or HuggingFace ID)"
    )

    # For file sources
    file_format: Optional[str] = Field(
        None, description="File format: 'csv', 'txt', 'json'"
    )

    # For HuggingFace sources - accepts ANY parameter that load_dataset supports
    huggingface_kwargs: Optional[Dict[str, Any]] = Field(
        None,
        description="Keyword arguments passed directly to HuggingFace load_dataset",
    )

    # For custom sources
    loader_class: Optional[str] = Field(
        None, description="Python import path for custom dataset loader"
    )
    loader_kwargs: Optional[Dict[str, Any]] = Field(
        None, description="Keyword arguments for custom loader"
    )

    @field_validator("type")
    def validate_type(cls, v):
        valid_types = {"file", "huggingface", "custom"}
        if v not in valid_types:
            raise ValueError(f"Dataset source type must be one of {valid_types}")
        return v


class DatasetConfig(BaseModel):
    """Complete dataset configuration."""

    source: DatasetSourceConfig
    prompt_column: Optional[str] = Field(
        None, description="Column name containing prompts"
    )
    image_column: Optional[str] = Field(
        None, description="Column name containing images"
    )
    prompt_lambda: Optional[str] = Field(
        None,
        description="Lambda expression string, "
        'e.g. \'lambda item: f"Question: {item["question"]}"\'',
    )
    unsafe_allow_large_images: bool = Field(
        False,
        description="Overrides pillows internal DDOS protection",
    )

    @classmethod
    def from_file(cls, config_path: str) -> "DatasetConfig":
        """Load configuration from a JSON file."""
        with open(config_path, "r") as f:
            data = json.load(f)
        return cls(**data)

    @classmethod
    def from_cli_args(
        cls,
        dataset_path: Optional[str] = None,
        prompt_column: Optional[str] = None,
        image_column: Optional[str] = None,
        **kwargs,
    ) -> "DatasetConfig":
        """Create configuration from CLI arguments for backward compatibility."""
        if dataset_path is None:
            # Default to built-in sonnet.txt
            dataset_path = str(Path(__file__).parent / "sonnet.txt")
            source_type = "file"
            file_format = "txt"
        else:
            # Determine source type from path
            path = Path(dataset_path)
            if path.exists():
                source_type = "file"
                if path.suffix == ".csv":
                    file_format = "csv"
                elif path.suffix == ".txt":
                    file_format = "txt"
                elif path.suffix == ".json":
                    file_format = "json"
                else:
                    raise ValueError(f"Unsupported file format: {path.suffix}")
            else:
                # Assume it's a HuggingFace ID
                source_type = "huggingface"
                file_format = None

        source_config = DatasetSourceConfig(
            type=source_type,
            path=dataset_path,
            file_format=file_format,
            huggingface_kwargs=None,
            loader_class=None,
            loader_kwargs=None,
        )

        return cls(
            source=source_config,
            prompt_column=prompt_column,
            image_column=image_column,
            prompt_lambda=None,
            unsafe_allow_large_images=False,
        )

"""Factory for creating appropriate data loaders and loading data."""

from typing import Any, List, Tuple, Union, cast

from genai_bench.data.config import DatasetConfig
from genai_bench.data.loaders.image import ImageDatasetLoader
from genai_bench.data.loaders.text import TextDatasetLoader
from genai_bench.logging import init_logger

logger = init_logger(__name__)


class DataLoaderFactory:
    """Factory for creating data loaders and loading data."""

    @staticmethod
    def load_data_for_task(
        task: str, dataset_config: DatasetConfig
    ) -> Union[List[str], List[Tuple[str, Any]]]:
        """Load data for a specific task.

        Args:
            task: Task name in format "input-to-output"
            dataset_config: Dataset configuration

        Returns:
            Loaded data for the task
        """
        input_modality, output_modality = task.split("-to-")

        if input_modality == "text":
            return DataLoaderFactory._load_text_data(dataset_config, output_modality)
        elif "image" in input_modality:
            return DataLoaderFactory._load_image_data(dataset_config)
        else:
            raise ValueError(f"Unsupported input modality: {input_modality}")

    @staticmethod
    def _load_text_data(
        dataset_config: DatasetConfig, output_modality: str
    ) -> List[str]:
        """Load text data."""

        loader = TextDatasetLoader(dataset_config)
        data = loader.load_request()

        # TextDatasetLoader always returns List[str]
        text_data = cast(List[str], data)
        return text_data

    @staticmethod
    def _load_image_data(
        dataset_config: DatasetConfig,
    ) -> List[Tuple[str, Any]]:
        """Load image data."""
        loader = ImageDatasetLoader(dataset_config)
        data = loader.load_request()
        return data  # type: ignore

from abc import ABC, abstractmethod
from enum import Enum
from typing import Any, List, Set, Tuple, Union

from PIL import Image as PILImage

from genai_bench.data.config import DatasetConfig
from genai_bench.data.sources import DatasetSourceFactory
from genai_bench.logging import init_logger

logger = init_logger(__name__)


class DatasetFormat(Enum):
    """Format supported for datasets in genai-bench."""

    TEXT = "txt"
    CSV = "csv"
    JSON = "json"
    HUGGINGFACE_HUB = "huggingface"


class DatasetLoader(ABC):
    """Abstract base class for dataset loader. A dataset loader is responsible for
    loading the data from a source using the new dataset configuration system.
    """

    supported_formats: Set[DatasetFormat] = set()
    media_type: str = ""

    def __init__(self, dataset_config: DatasetConfig):
        """Initialize with new dataset configuration."""
        self.dataset_config = dataset_config
        self._validate_source_format()
        self.dataset_source = DatasetSourceFactory.create(dataset_config.source)

    def _disable_pillow_decompresion_check(self):
        if self.dataset_config.unsafe_allow_large_images:
            logger.info("Disabling pillows decompression bomb protection.")
            PILImage.MAX_IMAGE_PIXELS = None

    def _validate_source_format(self):
        """Validate that the source format is supported by this loader."""
        source_type = self.dataset_config.source.type

        if source_type == "file":
            file_format = self.dataset_config.source.file_format
            if file_format:
                try:
                    format_enum = DatasetFormat(file_format.lower())
                except ValueError:
                    format_enum = None

                if format_enum and format_enum not in self.supported_formats:
                    raise ValueError(
                        f"File format '{file_format}' is not supported by "
                        f"{self.media_type} loader. Supported formats: "
                        f"{[f.value for f in self.supported_formats]}"
                    )
        elif source_type == "huggingface":
            if DatasetFormat.HUGGINGFACE_HUB not in self.supported_formats:
                raise ValueError(
                    f"HuggingFace datasets are not supported by "
                    f"{self.media_type} loader."
                )

    def load_request(self) -> Union[List[str], List[Tuple[str, Any]]]:
        """Load data from the dataset source."""
        self._disable_pillow_decompresion_check()
        data = self.dataset_source.load()
        return self._process_loaded_data(data)

    @abstractmethod
    def _process_loaded_data(
        self, data: Any
    ) -> Union[List[str], List[Tuple[str, Any]]]:
        """
        Process data loaded from dataset source. Must be implemented by subclasses.
        """
        pass

from typing import Any, List, Set

from genai_bench.data.loaders.base import DatasetFormat, DatasetLoader
from genai_bench.logging import init_logger

logger = init_logger(__name__)


class TextDatasetLoader(DatasetLoader):
    """
    This datasetLoader is responsible for loading prompts from a data source.

    TODO: Add support for prompt lambdas similar to ImageDatasetLoader.
    """

    supported_formats: Set[DatasetFormat] = {
        DatasetFormat.TEXT,
        DatasetFormat.CSV,
        DatasetFormat.JSON,
        DatasetFormat.HUGGINGFACE_HUB,
    }
    media_type = "Text"

    def _process_loaded_data(self, data: Any) -> List[str]:
        """Process data loaded from dataset source."""
        # Handle data from dataset sources
        if isinstance(data, list):
            return data

        # Handle dictionary data (from CSV files) or HuggingFace datasets
        prompt_column = self.dataset_config.prompt_column
        try:
            column_data = data[prompt_column]
            # Ensure we return a list of strings
            if isinstance(column_data, list):
                return [str(item) for item in column_data]
            else:
                # For HuggingFace datasets, convert to list
                return list(column_data)
        except (ValueError, KeyError) as e:
            # Provide helpful error message with available columns
            if isinstance(data, dict):
                available_columns = list(data.keys())
                raise ValueError(
                    f"Column '{prompt_column}' not found in CSV file. "
                    f"Available columns: {available_columns}"
                ) from e
            else:
                raise ValueError(
                    f"Cannot extract prompts from data: {type(data)}, error: {str(e)}"
                ) from e

"""Dataset source implementations for flexible dataset loading."""

import importlib
import os
from abc import ABC, abstractmethod
from pathlib import Path
from typing import Any, List, Tuple, Union

import pandas as pd
from datasets import load_dataset
from datasets.exceptions import DatasetNotFoundError
from huggingface_hub import dataset_info

from genai_bench.data.config import DatasetSourceConfig
from genai_bench.logging import init_logger

logger = init_logger(__name__)


class DatasetSource(ABC):
    """Abstract base class for dataset sources."""

    def __init__(self, config: DatasetSourceConfig):
        self.config = config

    @abstractmethod
    def load(self) -> Any:
        """Load dataset from source.

        Returns:
            The loaded dataset in a format suitable for the sampler.
        """
        pass


class FileDatasetSource(DatasetSource):
    """Load datasets from local files (txt, csv, json)."""

    def load(self) -> Union[List[str], List[Tuple[str, Any]]]:
        """Load data from local file."""
        if not self.config.path:
            raise ValueError("File path is required for file dataset source")

        file_path = Path(self.config.path)
        if not file_path.exists():
            raise FileNotFoundError(f"Dataset file not found: {file_path}")

        file_format = self.config.file_format or file_path.suffix.lstrip(".")

        if file_format == "txt":
            return self._load_text_file(file_path)
        elif file_format == "csv":
            return self._load_csv_file(file_path)
        elif file_format == "json":
            return self._load_json_file(file_path)
        else:
            raise ValueError(f"Unsupported file format: {file_format}")

    def _load_text_file(self, file_path: Path) -> List[str]:
        """Load text file line by line."""
        logger.info(f"Loading text file: {file_path}")
        with open(file_path, "r", encoding="utf-8") as f:
            lines = [line.strip() for line in f if line.strip()]
        logger.info(f"Loaded {len(lines)} lines from text file")
        return lines

    def _load_csv_file(self, file_path: Path) -> Any:
        """Load CSV file as a dictionary-like structure to support column names."""
        logger.info(f"Loading CSV file: {file_path}")

        # For CSV files, we'll return a pandas DataFrames
        df = pd.read_csv(file_path)
        logger.info(
            f"Loaded {len(df)} rows from CSV file with columns: {list(df.columns)}"
        )
        # Return a dict-like structure that supports column access
        return df.to_dict(orient="list")

    def _load_json_file(self, file_path: Path) -> List[Any]:
        """Load JSON file."""
        import json

        logger.info(f"Loading JSON file: {file_path}")
        with open(file_path, "r", encoding="utf-8") as f:
            data = json.load(f)

        if isinstance(data, list):
            logger.info(f"Loaded {len(data)} items from JSON file")
            return data
        else:
            raise ValueError(f"JSON file must contain a list, got {type(data)}")


class HuggingFaceDatasetSource(DatasetSource):
    """Load datasets from HuggingFace Hub with full flexibility."""

    def load(self) -> Any:
        """Load dataset from HuggingFace Hub."""
        if not self.config.path:
            raise ValueError("Dataset ID is required for HuggingFace dataset source")

        logger.info(f"Loading HuggingFace dataset: {self.config.path}")
        if self.config.huggingface_kwargs:
            logger.info(f"Using HuggingFace kwargs: {self.config.huggingface_kwargs}")

        kwargs = self.config.huggingface_kwargs or {}
        data_dir = Path(self.config.path).expanduser().resolve()
        is_local_data = data_dir.exists() and data_dir.is_dir()
        if not is_local_data:
            # Verify dataset exists
            try:
                dataset_info(self.config.path, token=os.environ.get("HF_TOKEN"))
            except DatasetNotFoundError as e:
                raise ValueError(
                    f"Dataset '{self.config.path}' not found on HuggingFace Hub. "
                    f"If it's a gated repo, please set HF_TOKEN environment "
                    f"variable."
                ) from e

        dataset = load_dataset(self.config.path, **kwargs)

        logger.info(f"Successfully loaded HuggingFace dataset: {self.config.path}")
        return dataset


class CustomDatasetSource(DatasetSource):
    """Load datasets using custom loader classes."""

    def load(self) -> Any:
        """Load dataset using custom loader."""
        if not self.config.loader_class:
            raise ValueError("Loader class is required for custom dataset source")

        # Import the custom loader class
        try:
            module_path, class_name = self.config.loader_class.rsplit(".", 1)
            module = importlib.import_module(module_path)
            loader_class = getattr(module, class_name)
        except (ImportError, AttributeError) as e:
            raise ImportError(
                f"Failed to import custom loader class "
                f"'{self.config.loader_class}': {e}"
            ) from e

        # Instantiate and use the loader
        kwargs = self.config.loader_kwargs or {}
        logger.info(f"Loading dataset with custom loader: {self.config.loader_class}")

        loader = loader_class(**kwargs)
        if hasattr(loader, "load"):
            return loader.load()
        else:
            raise AttributeError(
                f"Custom loader class '{self.config.loader_class}' must have a 'load' "
                f"method"
            )


class DatasetSourceFactory:
    """Factory to create appropriate dataset sources."""

    _sources = {
        "file": FileDatasetSource,
        "huggingface": HuggingFaceDatasetSource,
        "custom": CustomDatasetSource,
    }

    @classmethod
    def create(cls, config: DatasetSourceConfig) -> DatasetSource:
        """Create a dataset source based on configuration.

        Args:
            config: Dataset source configuration

        Returns:
            DatasetSource instance

        Raises:
            ValueError: If source type is not supported
        """
        source_type = config.type.lower()

        if source_type not in cls._sources:
            raise ValueError(
                f"Unknown dataset source type: {source_type}. "
                f"Supported types: {list(cls._sources.keys())}"
            )

        source_class = cls._sources[source_type]
        return source_class(config)  # type: ignore

    @classmethod
    def register_source(cls, source_type: str, source_class: type[DatasetSource]):
        """Register a new dataset source type.

        Args:
            source_type: Name of the source type
            source_class: Class implementing DatasetSource
        """
        cls._sources[source_type] = source_class

